var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"하아…… 멀다.","JPN":"はぁ……遠いな。","ENG":"*Sigh...* It's so far away.","TWN":"呼……好遠喔。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그래도 며칠 새 꽤 많이 걸었어.","JPN":"でも数日でかなり歩いたね。","ENG":"But I've closed the distance quite a lot in the last few days.","TWN":"這幾天走了好多路，"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"표지판이 맞다면 오늘 하루 부지런히 걸어가면 도착할 수 있을 거야.","JPN":"標識が正しければ、今日一日頑張って歩いたら到着できそう。","ENG":"If the signs are correct, then I should be there by the end of the day today.","TWN":"路標沒寫錯的話，應該今天再加點油就會到了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CORRUPTED_NPC_LUCID_PET","text":{"KOREA":"크릉.","JPN":"ガルン。","ENG":"Grr.","TWN":"呼嚕。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_10"},{"id":"L11_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"이제 다리가 보이기 시작했어.","JPN":"やっと橋が見えてきた。","ENG":"Finally, I can see the bridge.","TWN":"好像看到橋了。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그런데……","JPN":"ところで……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"어째서 앞에 검문소 같은 게 있는 거지? 군인들인 걸까?","JPN":"どうして橋の前に検問所みたいなものがあるんだろう？\\n政府軍の人たちかな？","ENG":"Is that a checkpoint in front of it? Are those people soldiers?","TWN":"前面那個是檢查哨吧？是軍人設的嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"군인이라면 도움을 받을 수 있을지도 모르지만…….","JPN":"政府軍なら助けてもらえるかもしれない……","ENG":"If they are, perhaps they can help me...","TWN":"是軍人的話，他們說不定會幫我……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"……아앗, 숨어!","JPN":"……あっ、隠れて！","ENG":"... Ah, duck!","TWN":"……啊！快躲起來！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CORRUPTED_NPC_LUCID_PET","text":{"KOREA":"킁!","JPN":"ガルン！","ENG":"Grr!","TWN":"呼嚕！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_11"},{"id":"L20_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"차가 지나갔어.","JPN":"車が行ったみたい。","ENG":"A car passed by.","TWN":"剛剛開過去的那台車上，"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"어린아이들도 타고 있는 것 같았는데…….","JPN":"幼い子どもたちが乗っていた気がする……","ENG":"I think there were children in it...","TWN":"似乎載著許多小孩……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CORRUPTED_NPC_LUCID_PET","text":{"KOREA":"크르륵!","JPN":"ガルルッ！","ENG":"Grrrrr!","TWN":"呼嚕嚕！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_13"},{"id":"L27_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"총소리! 검문소 방향이야!","JPN":"銃声！　検問所の方よ！","ENG":"Gunshots! From the checkpoint!","TWN":"有槍聲！是檢查哨的方向！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"엎드려! 엎드리라고!","JPN":"伏せろ！　伏せろと言ったんだ！","ENG":"Get down! Get down!","TWN":"趴下！我叫你趴下！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L32_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"왜, 왜들 이러십니까. 저흰 그냥 여길 통과하려고 했을 뿐인데요.","JPN":"ど、どうしたのですか。ワシらはここを通ろうとしただけです。","ENG":"Wh-why are you doing this? We're only trying to cross the bridge.","TWN":"你們這是在做什麼？我們不過是要通過這裡而已。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"방금 네 입으로 말했지. 국경으로 가는 길이라고 말이야.","JPN":"今お前の口で言っただろう。国境に行く途中だと。","ENG":"You just said you're going to the national border.","TWN":"你剛才說什麼？你說要要往國界去？？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"서, 설마 당신들! 정부군이 아니라……!","JPN":"ま、まさかあんたたち！　政府軍ではなく……！","ENG":"W-wait, you...? You're not government soldiers. You're—","TWN":"你…你們不是政府軍，是判……！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"딱 걸렸어. 이 망할 자식들. 동포들을 버리고 떠나면 잘 먹고 살 줄 알았나?","JPN":"このクソ野郎ども。同胞を見捨てて国を出て行けば気楽に暮らせるとでも思ったのか？","ENG":"I got you now, you traitors. You think you could be happy if you leave your people behind?","TWN":"被我逮個正著！該死的傢伙！你們以為拋下自己的同胞還能吃好睡好嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"전부 밖으로 끌어내려!","JPN":"全員引きずり下ろせ！","ENG":"Pull them all outside!","TWN":"全部給我帶到外面去！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"이, 이보게. 부탁이니 적어도 아이들만은……","JPN":"お、おい。お願いだからせめて子どもたちだけは……","ENG":"H-hey, please, I beg you. At least let the children go.","TWN":"年輕人，我拜託你，起碼讓孩子們……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"어이, 애들도 잔뜩 타고 있단다!","JPN":"おい、ガキどもも乗ってるってよ！","ENG":"Hey, they've got lots of children here, too!","TWN":"喂，老傢伙說車上有很多小孩！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"데려와 줘서 고마워, 형씨. 혁명군의 자금으로 잘 쓰도록 하지.","JPN":"連れてきてくれてありがとな、爺さん。革命軍の資金として使わせてもらうよ。","ENG":"Thank you for bringing them to us, mister. They'll help fund the revolutionary army.","TWN":"謝啦！把這些小孩送來給我們，就納作革命軍的財產囉！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"크흑…… 아, 안 돼.","JPN":"くっ……そ、そんな。","ENG":"Oh, no. No...!","TWN":"嗚嗚……不可以！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"멈춰요!","JPN":"やめてください！","ENG":"Stop!","TWN":"住手！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"음?","JPN":"あ？","ENG":"Mm?","TWN":"誰啊？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"뭐지? 넌 어디서 나타난 거야? 일행이냐?","JPN":"何だ？　お前はどこから出てきたんだ？　仲間か？","ENG":"What the...? Where did you come from? Are you with them?","TWN":"搞什麼？你又是從那裡冒出來的？是同夥的嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_03"},{"id":"L49_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그 사람들을 놓아 주세요. 당신들에겐 그럴 권리가 없어요.","JPN":"その方たちを放してください。あなたたちにそんなことをする権利はありません。","ENG":"Let them go. You have no right to do this.","TWN":"請放了那些人，你們沒有權力對他們做這些事！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"너, 총에 맞아 본 적 있냐?","JPN":"お前、銃で撃たれたことはあるか？","ENG":"Have you been shot at?","TWN":"你是沒被槍打過嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L3_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"다들 이게 무서워서 무릎을 꿇는다고.","JPN":"みんなこれが怖くて跪く。","ENG":"Everyone kneels to the ground when they see a gun.","TWN":"普通人看到槍都會嚇到腿軟，"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"정부군이건 난민이건 다 똑같이 총 앞에선 목숨을 구걸하는 추한 인간이란 말이지.","JPN":"政府軍だろうが難民だろうが、銃の前では命乞いをする醜い人間ってことだ。","ENG":"It doesn't matter if they're government soldiers or refugees. They all beg for life when held at gunpoint.","TWN":"無論是政府軍還是難民，在槍的面前不過就是搖尾乞憐的一群人。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"너라고 다를 것 같아?","JPN":"お前は違うとでも思ってるのか？","ENG":"You're no different.","TWN":"你以為你跟他們不一樣嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"……적어도 당신들과는 달라요.","JPN":"……少なくともあなたたちとは違います。","ENG":"... At least I'm different from you.","TWN":"……至少我和你們不一樣！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"총소리에 취해서 사람들을 괴롭히는 당신들과는요.","JPN":"武力を盾に、他人を苦しめるあなたたちとは違います。","ENG":"At least I don't terrorize others because I have a gun.","TWN":"我才不會像你們一樣拿著槍在那作威作福。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"흥.","JPN":"ふん。","ENG":"Hmpf.","TWN":"哼！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"좋아. 그런 식으로 나오겠다 이거지.","JPN":"いいだろう。そう来るか。","ENG":"Alright, so this is how it's going to be, is it?","TWN":"很好，你以為你是驚奇隊長是吧？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"겉으로만 번지르르한 말을 늘어놓는 꼴이 정부 놈들과 한통속이 틀림없군.","JPN":"上辺だけの綺麗事を並べているあたり、政府の連中に違いない。","ENG":"You're talking big and noble, just like the government bureaucrats.","TWN":"我看你滿嘴大道理的樣子，肯定是和政府軍是一夥的！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"그 면전에 총알이 박힌 뒤에도 그런 말을 할 수 있을지 볼까?","JPN":"そのツラに銃弾がぶち込まれた後もそんなことを言えるのか確かめてやる！","ENG":"Let's see if you still can talk after I stick a bullet into your face.","TWN":"我倒要看看你吃了子彈後，嘴巴還能那麼厲害嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L17_1","type":"dialog","speaker":"SOLDIER_NPC_REVELA_NULL","text":{"KOREA":"……뭐, 뭐야? 방금 그 소리?","JPN":"……な、なんだ？　今の音は？","ENG":"... Wh-what was that? What was that noise?","TWN":"這……這是什麼？剛才那是什麼聲音？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_REVELA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};